static int fibonacci(int n) {
    if (n &lt;= 1) return n;  // base cases
    return fibonacci(n - 1) + fibonacci(n - 2);
}

for (int i = 0; i &lt; 8; i++) {
    System.out.print(fibonacci(i) + " ");
}
